// ANTI-AI DETECTION RULES (MANDATORY FOR ALL CUSTOMER-FACING CONTENT):
// - NEVER use: delve, leverage, utilize, harness, elevate, empower, streamline, robust, seamless, cutting-edge, game-changer, innovative, revolutionize, best-in-class, holistic, synergy, paradigm
// - NEVER use em dashes (use regular dashes)
// - ALWAYS use contractions (I'm, can't, won't, you're, we're, it's, don't, isn't)
// - Vary sentence length (some 3 words, some 30)
// - Include casual imperfections (start with "And" or "But", sentence fragments OK)
// - Sound like a real person typing, not a marketing team
// - Keep paragraphs short (1-3 sentences)
// - Write at 8th grade reading level

const payload = $input.first().json.body || $input.first().json;
const email = (payload.email || '').trim().toLowerCase();
const businessId = payload.businessId || 'bayflow';
const outcome = payload.outcome || 'interested';
const notes = payload.notes || '';
const nextSteps = payload.next_steps || '';
const firstName = email.split('@')[0].replace(/[._]/g, ' ').split(' ')[0];

if (!email) {
  throw new Error('Missing required field: email');
}

const validOutcomes = ['interested', 'needs_time', 'not_interested', 'no_show'];
if (!validOutcomes.includes(outcome)) {
  throw new Error('Invalid outcome. Must be one of: ' + validOutcomes.join(', '));
}

// Look up business details from Supabase
const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6IndqdWtmZHppb21uZWp0bG1lZ3Z2Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM1Mjk1ODIsImV4cCI6MjA4OTEwNTU4Mn0.12Vszqd1Lhp0M6FIB_pSF1l7T_SscB0X4AxwFTRrTVU';
let _bizName = 'BayFlow';
let _bizDomain = 'bayflow.com';
let _bizFromEmail = 'shalin@bayflow.com';
let _bizAppUrl = 'https://app.bayflow.com';
let _bizDescription = 'Shop management software for independent auto repair shops';

try {
  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/businesses?business_id=eq.${encodeURIComponent(businessId)}&select=name,site_url,sending_domain,tagline`,
    { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}` } }
  );
  const rows = await resp.json();
  if (rows && rows[0]) {
    _bizName = rows[0].name || _bizName;
    _bizDomain = rows[0].sending_domain || (rows[0].site_url || '').replace(/^https?:\/\//, '').replace(/\/.*$/, '') || _bizDomain;
    _bizFromEmail = 'shalin@' + _bizDomain;
    _bizAppUrl = rows[0].site_url ? rows[0].site_url.replace(/^(https?:\/\/)/, '$1app.') : _bizAppUrl;
    _bizDescription = rows[0].tagline || _bizDescription;
  }
} catch (e) {}

return [{
  json: {
    email,
    businessId,
    outcome,
    notes,
    nextSteps,
    firstName,
    now: $now.toFormat('yyyy-MM-dd HH:mm:ss'),
    _bizName,
    _bizDomain,
    _bizFromEmail,
    _bizAppUrl,
    _bizDescription
  }
}];

const data = $('Parse Demo Payload').first().json;
const now = new Date();
const followUp = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000);
const followUpDate = followUp.toISOString().split('T')[0];

return [{ json: { ...data, nextFollowUpDate: followUpDate } }];

const response = $input.all().map(i => i.json);
const leads = Array.isArray(response[0]) ? response[0] : response;
const valid = leads.filter(l => l.email);

if (valid.length === 0) {
  return [{ json: { _empty: true, count: 0 } }];
}

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6IndqdWtmZHppb21uZWp0bG1lZ3Z2Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM1Mjk1ODIsImV4cCI6MjA4OTEwNTU4Mn0.12Vszqd1Lhp0M6FIB_pSF1l7T_SscB0X4AxwFTRrTVU';
const bizCache = {};
async function lookupBiz(bizId) {
  if (!bizId || bizCache[bizId]) return bizCache[bizId] || { name: 'BayFlow', domain: 'bayflow.com', fromEmail: 'shalin@bayflow.com', appUrl: 'https://app.bayflow.com', desc: '' };
  try {
    const r = await fetch(`${SUPABASE_URL}/rest/v1/businesses?business_id=eq.${encodeURIComponent(bizId)}&select=name,site_url,sending_domain,tagline`, { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}` } });
    const rows = await r.json();
    if (rows && rows[0]) {
      const b = rows[0];
      const domain = b.sending_domain || (b.site_url || '').replace(/^https?:\/\//, '').replace(/\/.*$/, '') || 'bayflow.com';
      bizCache[bizId] = { name: b.name || bizId, domain, fromEmail: 'shalin@' + domain, appUrl: b.site_url ? b.site_url.replace(/^(https?:\/\/)/, '$1app.') : 'https://app.bayflow.com', desc: b.tagline || '' };
      return bizCache[bizId];
    }
  } catch (e) {}
  return { name: 'BayFlow', domain: 'bayflow.com', fromEmail: 'shalin@bayflow.com', appUrl: 'https://app.bayflow.com', desc: '' };
}

const results = [];
for (const l of valid) {
  const bizId = l.business_id || 'bayflow';
  const biz = await lookupBiz(bizId);
  results.push({
    json: {
      _empty: false,
      email: l.email,
      firstName: l.first_name || l.email.split('@')[0].replace(/[._]/g, ' ').split(' ')[0],
      businessName: l.business_name || '',
      businessId: bizId,
      _bizName: biz.name,
      _bizFromEmail: biz.fromEmail,
      _bizAppUrl: biz.appUrl,
      _bizDescription: biz.desc
    }
  });
}
return results;

const now = new Date();
// 12 days ago
const d12 = new Date(now.getTime() - 12 * 24 * 60 * 60 * 1000);
// 14 days ago (start of window = trials started 12-13 days ago)
const d14 = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);

// We want trial_started_at between d14 and d12 (i.e., 12-13 days ago)
const rangeStart = d14.toISOString().split('T')[0];
const rangeEnd = d12.toISOString().split('T')[0];

return [{ json: { rangeStart, rangeEnd } }];

